class alerts_table extends DB_Table
{
	var $col = array(
	'idalerts' => array( 'type'=>'int', 'require'=>false, 'size' =>'11' ),
	'alertdescription' => array( 'type'=>'varchar', 'require'=>true, 'size' =>'45' ),
	'alertfunctionname' => array( 'type'=>'varchar', 'require'=>true, 'size' =>'45' ),
	'expirydate' => array( 'type'=>'date', 'require'=>false, 'size' =>'11' ),
	);
};
require_once( 'DB/DataObject.php' );;

class alerts_object extends DB_DataObject
{
	var $__table='alerts';
		//This is a Structures/DataGrid object
	var $idalerts;
	var $alertdescription;
	var $alertfunctionname;
	var $expirydate;
