/*	view/QuickFormIncludes and TabbedPages.php are in the skel-app/view if required	*/
require_once( 'view/QuickFormIncludes.php' );;
require_once( 'view/TabbedPages.php' );;

class alerts_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('alerts page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idalerts = $fs->addElement('text', 'idalerts', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'index' )
;
		$alertdescription = $fs->addElement('text', 'alertdescription', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Description' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'alertdescription Field Required' );
		$alertfunctionname = $fs->addElement('text', 'alertfunctionname', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Called Function' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'alertfunctionname Field Required' );
		$f_date = date("Y-m-d" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'expirydate' => $f_date ) ) );
		$expirydate = $fs->addElement('text', 'expirydate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Expiry Date of Alert' )
			->addFilter( 'trim' )
;
	}
}
